6767 /// Return true if undefined behavior would provably be executed on the path to
6768 /// OnPathTo if Root produced a posion result.  Note that this doesn't say
6769 /// anything about whether OnPathTo is actually executed or whether Root is
6770 /// actually poison.  This can be used to assess whether a new use of Root can
6771 /// be added at a location which is control equivalent with OnPathTo (such as
6772 /// immediately before it) without introducing UB which didn't previously
6773 /// exist.  Note that a false result conveys no information.
6774 bool llvm::mustExecuteUBIfPoisonOnPathTo(Instruction *Root,
6775                                          Instruction *OnPathTo,
6776                                          DominatorTree *DT) {
6777   // Basic approach is to assume Root is poison, propagate poison forward
6778   // through all users we can easily track, and then check whether any of those
6779   // users are provable UB and must execute before out exiting block might
6780   // exit.
6781 
6782   // The set of all recursive users we've visited (which are assumed to all be
6783   // poison because of said visit)
6784   SmallSet<const Value *, 16> KnownPoison;
6785   SmallVector<const Instruction*, 16> Worklist;
6786   Worklist.push_back(Root);
6787   while (!Worklist.empty()) {
6788     const Instruction *I = Worklist.pop_back_val();
6789 
6790     // If we know this must trigger UB on a path leading our target.
6791     if (mustTriggerUB(I, KnownPoison) && DT->dominates(I, OnPathTo))
6792       return true;
6793 
6794     // If we can't analyze propagation through this instruction, just skip it
6795     // and transitive users.  Safe as false is a conservative result.
6796     if (I != Root && !any_of(I->operands(), [&KnownPoison](const Use &U) {
6797           return KnownPoison.contains(U) && propagatesPoison(U);
6798         }))
6799       continue;
6800 
6801     if (KnownPoison.insert(I).second)
6802       for (const User *User : I->users())
6803         Worklist.push_back(cast<Instruction>(User));
6804   }
6805 
6806   // Might be non-UB, or might have a path we couldn't prove must execute on
6807   // way to exiting bb.
6808   return false;
6809 }
