6564 static bool directlyImpliesPoison(const Value *ValAssumedPoison,
6565                                   const Value *V, unsigned Depth) {
6566   if (ValAssumedPoison == V)
6567     return true;
6568 
6569   const unsigned MaxDepth = 2;
6570   if (Depth >= MaxDepth)
6571     return false;
6572 
6573   if (const auto *I = dyn_cast<Instruction>(V)) {
6574     if (any_of(I->operands(), [=](const Use &Op) {
6575           return propagatesPoison(Op) &&
6576                  directlyImpliesPoison(ValAssumedPoison, Op, Depth + 1);
6577         }))
6578       return true;
6579 
6580     // V  = extractvalue V0, idx
6581     // V2 = extractvalue V0, idx2
6582     // V0's elements are all poison or not. (e.g., add_with_overflow)
6583     const WithOverflowInst *II;
6584     if (match(I, m_ExtractValue(m_WithOverflowInst(II))) &&
6585         (match(ValAssumedPoison, m_ExtractValue(m_Specific(II))) ||
6586          llvm::is_contained(II->args(), ValAssumedPoison)))
6587       return true;
6588   }
6589   return false;
6590 }
